const formatMessage = require('format-message');
const BlockType = require('../../extension-support/block-type');
const ArgumentType = require('../../extension-support/argument-type');
const Cast = require('../../util/cast');

// eslint-disable-next-line max-len
const iconURI = `data:image/svg+xml;base64,`;

/**
 * Class for TurboWarp blocks
 * @constructor
 */
class gce3 {
    constructor (runtime) {
        /**
         * The runtime instantiating this block package.
         * @type {Runtime}
         */
        this.runtime = runtime;
    }

    /**
     * @returns {object} metadata for this extension and its blocks.
     */
    getInfo () {
        return {
            id: 'gce3',
            name: formatMessage({
                id: 'cc.gce3.name',
                default: 'Geometric Calculations',
                description: null
            }),
            menuIconURI: iconURI,
            blockIconURI: iconURI,
            blocks: [
                {
                    opcode: 'triangleArea',
                    text: formatMessage({
                        id: 'cc.gce3.blocks.triangleArea',
                        default: 'area of a triangle with base [BASE] and height [HEIGHT]',
                        description: 'Block that calculates the area of a triangle given its base and height'
                    }),
                    blockType: BlockType.REPORTER,
                    arguments: {
                        BASE: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        },
                        HEIGHT: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        }
                    }
                },
                {
                    opcode: 'triangleAreaUnits',
                    text: formatMessage({
                        id: 'cc.gce3.blocks.triangleAreaUnits',
                        default: 'area of a triangle with base [BASE] and height [HEIGHT] in [UNITS]',
                        description: 'Block that calculates the area of a triangle given its base and height'
                    }),
                    blockType: BlockType.REPORTER,
                    arguments: {
                        BASE: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        },
                        HEIGHT: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        },
                        UNITS: {
                            type: ArgumentType.NUMBER,
                            menu: 'units',
                            defaultValue: '0'
                        }
                    }
                },
                {
                    opcode: 'rectangleArea',
                    text: formatMessage({
                        id: 'cc.gce3.blocks.rectangleArea',
                        default: 'area of a rectangle with horizontal [HORIZONTAL] and vertical [VERTICAL]',
                        description: 'Block that returns whether a specific mouse button is down'
                    }),
                    blockType: BlockType.REPORTER,
                    arguments: {
                        HORIZONTAL: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        },
                        VERTICAL: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        }
                    }
                },
                {
                    opcode: 'rectangleAreaUnits',
                    text: formatMessage({
                        id: 'cc.gce3.blocks.rectangleAreaUnits',
                        default: 'area of a rectangle with horizontal [HORIZONTAL] and vertical [VERTICAL] in [UNITS]',
                        description: 'Block that returns whether a specific mouse button is down'
                    }),
                    blockType: BlockType.REPORTER,
                    arguments: {
                        HORIZONTAL: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        },
                        VERTICAL: {
                            type: ArgumentType.NUMBER,
                            defaultValue: '100'
                        },
                        UNITS: {
                            type: ArgumentType.NUMBER,
                            menu: 'units',
                            defaultValue: '0'
                        }
                    }
                }
            ],
            menus: {
                units: {
                    items: [
                        {
                            text: formatMessage({
                                id: 'cc.gce3.blocks.units.cm',
                                default: 'cm',
                                description: 'Dropdown item to select centimeters as units'
                            }),
                            value: '0'
                        },
                        {
                            text: formatMessage({
                                id: 'cc.gce3.blocks.units.m',
                                default: 'm',
                                description: 'Dropdown item to select meters as units'
                            }),
                            value: '1'
                        },
                        {
                            text: formatMessage({
                                id: 'cc.gce3.blocks.units.km',
                                default: 'km',
                                description: 'Dropdown item to select kilometers as units'
                            }),
                            value: '2'
                        },
                        {
                            text: formatMessage({
                                id: 'cc.gce3.blocks.units.a',
                                default: 'a',
                                description: 'Dropdown item to select a (are) as units'
                            }),
                            value: '3'
                        },
                        {
                            text: formatMessage({
                                id: 'cc.gce3.blocks.units.ha',
                                default: 'ha',
                                description: 'Dropdown item to select ha (hectare) as units'
                            }),
                            value: '4'
                        }
                    ],
                    acceptReporters: true
                }
            }
        };
    }

    triangleArea (args, util) {
        const base = Cast.toNumber(args.BASE);
        const height = Cast.toNumber(args.HEIGHT);
        return (base * height) / 2;
    }

    triangleAreaUnits (args, util) {
        const base = Cast.toNumber(args.BASE);
        const height = Cast.toNumber(args.HEIGHT);
        const units = Cast.toNumber(args.UNITS);
        const anser = (base * height) / 2;
        return `${anser}${units === 0 ? 'cm²' : units === 1 ? 'm²' : units === 2 ? 'km²' : units === 3 ? 'a' : units === 4 ? 'ha' : ''}`;
    }

    rectangleArea (args, util) {
        const horizontal = Cast.toNumber(args.HORIZONTAL);
        const vertical = Cast.toNumber(args.VERTICAL);
        return horizontal * vertical;
    }

    rectangleAreaUnits (args, util) {
        const horizontal = Cast.toNumber(args.HORIZONTAL);
        const vertical = Cast.toNumber(args.VERTICAL);
        const units = Cast.toNumber(args.UNITS);
        const anser = horizontal * vertical;
        return `${anser}${units === 0 ? 'cm²' : units === 1 ? 'm²' : units === 2 ? 'km²' : units === 3 ? 'a' : units === 4 ? 'ha' : ''}`
    }
}

module.exports = gce3;
